  GetLoanTypeSteps(loanTypeCode: number) {
    if (this.workflowAllowed == 1) {
      this.http
        .post<Step[]>(
          this.env.API_URL + `api/Loan/GetLoanTypeSteps`,
          loanTypeCode
        )
        .subscribe({
          next: async (data) => {
            this.steps = data;
            if (this.steps.length == 0) {
              this.steps = [
                {
                  step_id: 0,
                  next_step: null,
                  job_id: -1,
                  step_name: "خطوة أولية",
                  loan_type_code: parseInt(this.typeChosen.loan_type_code),
                  org_code: this.typeChosen.org_code,
                  enable_accept: 1,
                  enable_reject: 1,
                },
              ];
            }
            this.documentsInformation.documentsByStep = [];
            this.steps.forEach((x) => {
              this.addingNewStepInsideDocuments(
                x.step_id,
                x.job_id,
                x.loan_type_code
              );
            });
          },
          error: async (err) => {
            console.log(err);
            await this.FailureAlert(err.message);
            this.BackToInitial();
          },
        });
    }
  }

  async GetLoanTypeInfo(): Promise<any> {
    return new Promise(async (resolve, reject) => {
      await this.http
        .get<any>(
          this.env.API_URL +
            `api/Loan/GetLoanTypeInfo?loanTypeCode=${this.typeChosen.loan_type_code}`
        )
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            resolve(data);
          },
          error: (err) => {
            this.showLoader = false;
            reject(err);
          },
        });
    });
  }

