  async StepSubmit(create: boolean) {
    if (this.stepDetails.valid) {
      var step: Step = {
        org_code:
          this.typeChosen !== undefined && this.typeChosen !== null
            ? this.typeChosen.org_code
            : null,
        loan_type_code:
          this.typeChosen !== undefined && this.typeChosen !== null
            ? parseInt(this.typeChosen.loan_type_code)
            : null,
        next_step:
          this.stepDetailsControls.nextStep.value == -1
            ? null
            : this.stepDetailsControls.nextStep.value,
        step_id: create
          ? this.steps.reduce((highest, value) => {
              return (highest =
                highest > value.step_id ? highest : value.step_id);
            }, 0) + 1
          : this.selectedStep.step_id,
        job_id: parseInt(this.stepDetailsControls.job.value),
        step_name: this.stepDetailsControls.stepName.value,
        step_days: this.stepDetailsControls.stepDays.value,
        step_hours: this.stepDetailsControls.stepHours.value,
        step_minutes: this.stepDetailsControls.stepMinutes.value,
        enable_accept: this.ConvertBooleanToInt(
          Array.from(this.stepDetailsControls.actions.value).includes(1)
        ),
        enable_reject: this.ConvertBooleanToInt(
          Array.from(this.stepDetailsControls.actions.value).includes(2)
        ),
        enable_accept_with_edit: this.ConvertBooleanToInt(
          Array.from(this.stepDetailsControls.actions.value).includes(3)
        ),
        enable_reverse: this.ConvertBooleanToInt(
          Array.from(this.stepDetailsControls.actions.value).includes(4)
        ),
        enable_freeze: this.ConvertBooleanToInt(
          Array.from(this.stepDetailsControls.actions.value).includes(5)
        ),
        enable_exception: this.ConvertBooleanToInt(
          Array.from(this.stepDetailsControls.actions.value).includes(7)
        ),
        location_required:
          this.stepDetailsControls.locationRequired.value !== null
            ? this.ConvertBooleanToInt(
                this.stepDetailsControls.locationRequired.value
              )
            : 0,
      };
      if (create) {
        this.steps = this.steps.concat([step]);
        this.processDocumentSubmission(this.steps);
      } else {
        this.steps = this.steps.filter(
          (x) => x.step_id != this.selectedStep.step_id
        );
        this.steps = this.steps
          .concat([step])
          .sort((n1, n2) => n1.step_id - n2.step_id);
        this.documentsInformation.documentsByStep.find(
          (x) =>
            x.stepId === this.selectedStep.step_id &&
            x.loanTypeCode === this.selectedStep.loan_type_code
        ).jobId = parseInt(this.stepDetailsControls.job.value);
      }
    } else {
      const foundIndex = this.findIndexOfSpecificStepFromDocumentsArray(
        0,
        0,
        0
      );
      if (foundIndex !== -1) {
        this.documentsInformation.documentsByStep.splice(foundIndex, 1);
      }
      await this.FailureAlert("بيانات الخطوة غير صحيحة");
    }
    this.isStepDetailsSubmitted = true;
    console.log("this.steps", this.steps);
  }

