  ConvertBooleanToInt(intIn): number {
    switch (typeof intIn) {
      case "boolean":
        return intIn == true ? 1 : 0;
      case "number":
        return intIn;
      default:
        return 0;
    }
  }

  async RemoveStep(step: Step) {
    if (step.step_id != 0) {
      this.steps = this.steps.filter((x) => x.step_id != step.step_id);
      this.steps.forEach((x) => {
        if (x.next_step === step.step_id) {
          x.next_step = null;
        }
      });
      const stepIndexToDelete = this.findIndexOfSpecificStepFromDocumentsArray(
        step.step_id,
        step.job_id,
        step.loan_type_code
      );
      this.documentsInformation.documentsByStep.splice(stepIndexToDelete, 1);
    } else {
      await this.FailureAlert("لا يمكن إزالة الخطوة الأولية");
    }
  }

  getStepActions(step: Step): number[] {
    var result: number[] = [];
    if (step.enable_accept == 1) result = result.concat(1);
    if (step.enable_reject == 1) result = result.concat(2);
    if (step.enable_accept_with_edit == 1) result = result.concat(3);
    if (step.enable_reverse == 1) result = result.concat(4);
    if (step.enable_freeze == 1) result = result.concat(5);
    if (step.enable_exception == 1) result = result.concat(7);

    return result;
  }

