  isDocumentChecked = (document: DocumentType): boolean => {
    const currentStepId: number = this.selectedStep.step_id;
    const currentLoanTypeCode: number = this.selectedStep.loan_type_code;
    const currentJobId: number = this.selectedStep.job_id;
    const documentTypeCode: string = document.documentTypeCode;

    const selectedStep = this.documentsInformation.documentsByStep.find(
      (x) =>
        x.stepId === currentStepId &&
        x.jobId === currentJobId &&
        x.loanTypeCode === currentLoanTypeCode
    );
    const isDocumentTypeCodeIsSelectedInSameStep =
      selectedStep.selectedDocuments.some((selectedDoc) => {
        return selectedDoc.selectedDocumentTypeCode === documentTypeCode;
      });
    return isDocumentTypeCodeIsSelectedInSameStep;
  };
  isLoanTypeHasDocumentsSelected = (): boolean => {
    const currentStepId: number = this.selectedStep.step_id;
    const currentLoanTypeCode: number = this.selectedStep.loan_type_code;
    const currentJobId: number = this.selectedStep.job_id;

    if (this.documentsInformation.documentsByStep.length === 0) {
      return;
    }
    const selectedStep = this.documentsInformation.documentsByStep.find(
      (x) =>
        x.stepId === currentStepId &&
        x.jobId === currentJobId &&
        x.loanTypeCode === currentLoanTypeCode
    );

    return !!selectedStep?.isRequiredFlag;
  };
  makeSpecificDocument = (document: DocumentType): void => {
    const currentStepId: number = this.selectedStep.step_id;
    const currentJobId: number = this.selectedStep.job_id;
    const currentLoanTypeCode: number = this.selectedStep.loan_type_code;
    const documentTypeCode: string = document.documentTypeCode;
    let selectedStep = this.documentsInformation.documentsByStep.find(
      (x) =>
        x.stepId === currentStepId &&
        x.jobId === currentJobId &&
        x.loanTypeCode === currentLoanTypeCode
    );

    let isArrayContainThisDocument = selectedStep.selectedDocuments.some(
      (x) => x.selectedDocumentTypeCode === documentTypeCode
    );

    if (!isArrayContainThisDocument) {
      selectedStep.selectedDocuments.push({
        isThisDocumentMustEnter: false,
        selectedDocumentTypeCode: documentTypeCode,
      });
      return;
    }
    selectedStep.selectedDocuments = selectedStep.selectedDocuments.filter(
      (x) => x.selectedDocumentTypeCode !== documentTypeCode
    );
  };
  assignDocumentToMustUse = (document: DocumentType): void => {
    const currentStepId: number = this.selectedStep.step_id;
    const currentJobId: number = this.selectedStep.job_id;
    const currentLoanTypeCode: number = this.selectedStep.loan_type_code;
    const documentTypeCode: string = document.documentTypeCode;
    let selectedStep = this.documentsInformation.documentsByStep.find(
      (x) =>
        x.stepId === currentStepId &&
        x.jobId === currentJobId &&
        x.loanTypeCode === currentLoanTypeCode
    );
    let selectedDocumentForSpecificDocumentType =
      selectedStep.selectedDocuments.filter(
        (x) => x.selectedDocumentTypeCode === documentTypeCode
      )[0];

    selectedDocumentForSpecificDocumentType.isThisDocumentMustEnter =
      !selectedDocumentForSpecificDocumentType.isThisDocumentMustEnter;
  };
